  geminiModel: 'gemini-2.0-flash-exp',
  geminiUrl: 'https://generativelanguage.googleapis.com/v1beta/models/',
  openaiUrl: 'https://api.openai.com/v1/chat/completions',
  geminiApiKey: process.env.GEMINI_API_KEY || 'PASTE_GEMINI_API_KEY_HERE',
  openaiApiKey: process.env.OPENAI_API_KEY || 'PASTE_OPENAI_API_KEY_HERE',
  designSystem: {
    colors: {
      ink: '#1A1A1A', inkLight: '#555555',
      accent: '#E85D3A', accentDark: '#C94B2A', accentLight: '#FFF3EE',
      background: '#FFFFFF', surface: '#F7F5F2',
      success: '#3AAF6B', error: '#E04848',
      golden: '#FFD93D', sky: '#7EC8E3', mint: '#6BCB77', lavender: '#B4A7D6'
    },
    typography: { heading: 'Fredoka One', body: 'Nunito', comic: 'Comic Neue' },
    borderRadius: { sm: 8, md: 12, lg: 16, xl: 20, pill: 100 },
    spacing: { xs: 4, sm: 8, md: 16, lg: 24, xl: 32 }
  },
  stylePrefix: 'Children comic app illustration. Hand-drawn cartoon style, bold 2px black outlines (#1A1A1A), rounded friendly shapes, minimal shading, flat colors. Palette: warm orange (#E85D3A), cream (#F7F5F2), golden yellow (#FFD93D), sky blue (#7EC8E3), mint green (#6BCB77), lavender (#B4A7D6). Playful, expressive, child-friendly. Clean digital illustration with comic book energy.'
