const dirs = [
  'branding', 'ui-components', 'characters', 'onboarding',
  'empty-states', 'backgrounds', 'comic-elements', 'icons',
  'avatars', 'animations', 'design-system'
];
dirs.forEach(d => fs.mkdirSync(config.outputPath + '/' + d, { recursive: true }));

return [{ json: config }];

const config = $input.first().json;

try {
  const resp = await fetch(config.openaiUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + config.openaiApiKey
    },
    body: JSON.stringify({
      model: 'gpt-4o-mini',
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'system',
          content: 'You are a mobile design system expert for children cartoon/comic apps. Return a complete design system as a single JSON object.'
        },
        {
          role: 'user',
          content: 'Create a comprehensive design system JSON for ' + config.appName + ', a comic generator app for children aged 5-13. Base palette: ' + JSON.stringify(config.designSystem.colors) + '. Typography: ' + JSON.stringify(config.designSystem.typography) + '. Include: colorPalette with semantic names and usage rules, typographyScale (h1-h4 body caption button), spacingScale, borderRadiusScale, shadowDefinitions (card lifted soft comic), componentSpecs (button variants with states, card, badge, input, modal, bottomNav), iconStyle guidelines, illustrationRules (line weight colors expressions composition), animationTokens (durations easings spring configs), accessibilityNotes (contrast touch-targets font-sizes).'
        }
      ],
      max_tokens: 3000
    })
  });

  const data = await resp.json();
  let enriched = {};
  try {
    enriched = JSON.parse(data.choices[0].message.content);
  } catch (e) {
    enriched = { raw: data.choices[0].message.content };
  }

  const fs = require('fs');
  const dsOutput = {
    base: config.designSystem,
    enriched: enriched,
    generatedAt: new Date().toISOString()
  };
  fs.writeFileSync(
    config.outputPath + '/design-system/design-system.json',
    JSON.stringify(dsOutput, null, 2)
  );

  return [{ json: { ...config, designSystemStatus: 'success' } }];
} catch (e) {
  return [{ json: { ...config, designSystemStatus: 'error', dsError: e.message } }];
}

