const item = $input.first().json;
const fs = require('fs');

try {
  const url = item.config.geminiUrl + item.config.geminiModel + ':generateContent?key=' + item.config.geminiApiKey;

  const resp = await fetch(url, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      contents: [{ parts: [{ text: item.prompt }] }],
      generationConfig: {
        responseModalities: ['IMAGE', 'TEXT'],
        temperature: 0.8
      }
    })
  });

  const data = await resp.json();

  if (data.error) {
    return [{ json: { id: item.id, name: item.name, category: item.category, status: 'api_error', error: data.error.message || JSON.stringify(data.error) } }];
  }

  const parts = (data.candidates && data.candidates[0] && data.candidates[0].content && data.candidates[0].content.parts) || [];
  const imgPart = parts.find(function(p) { return p.inlineData; });

  if (imgPart) {
    const buf = Buffer.from(imgPart.inlineData.data, 'base64');
    fs.writeFileSync(item.filename, buf);
    return [{ json: { id: item.id, name: item.name, category: item.category, filename: item.filename, status: 'success', sizeBytes: buf.length } }];
  }

  return [{ json: { id: item.id, name: item.name, category: item.category, status: 'no_image', response: JSON.stringify(data).substring(0, 500) } }];
} catch (e) {
  return [{ json: { id: item.id, name: item.name, category: item.category, status: 'error', error: e.message } }];
}

