const item = $input.first().json;
const fs = require('fs');

try {
  const apiKey = item.config.openaiApiKey || process.env.OPENAI_API_KEY;
  const apiUrl = item.config.openaiUrl || 'https://api.openai.com/v1/chat/completions';

  const resp = await fetch(apiUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ' + apiKey
    },
    body: JSON.stringify({
      model: 'gpt-4o-mini',
      messages: [
        {
          role: 'system',
          content: 'You are a Lottie animation expert. Generate valid Lottie JSON animation files. Output ONLY the raw Lottie JSON object. No markdown, no explanation, no code fences. Just the JSON object starting with { and ending with }.'
        },
        {
          role: 'user',
          content: item.lottiePrompt
        }
      ],
      temperature: 0.2,
      max_tokens: 4000
    })
  });

  const data = await resp.json();
  const content = data.choices[0].message.content;

  let lottieJson;
  try {
    lottieJson = JSON.parse(content);
  } catch (parseErr) {
    var match = content.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (match) {
      lottieJson = JSON.parse(match[1].trim());
    } else {
      var braceStart = content.indexOf('{');
      var braceEnd = content.lastIndexOf('}');
      if (braceStart !== -1 && braceEnd !== -1) {
        lottieJson = JSON.parse(content.substring(braceStart, braceEnd + 1));
      } else {
        lottieJson = { error: 'Could not parse Lottie JSON', rawResponse: content.substring(0, 500) };
      }
    }
  }

  fs.writeFileSync(item.filename, JSON.stringify(lottieJson, null, 2));
  return [{ json: { id: item.id, name: item.name, filename: item.filename, status: 'success' } }];
} catch (e) {
  return [{ json: { id: item.id, name: item.name, status: 'error', error: e.message } }];
}

const fs = require('fs');
const basePath = '/tmp/mangakids-assets';

function scanDir(dir) {
  var results = [];
  try {
    var items = fs.readdirSync(dir, { withFileTypes: true });
    for (var i = 0; i < items.length; i++) {
      var fullPath = dir + '/' + items[i].name;
      if (items[i].isDirectory()) {
        results = results.concat(scanDir(fullPath));
      } else {
        var stats = fs.statSync(fullPath);
        results.push({
          path: fullPath.replace(basePath + '/', ''),
          filename: items[i].name,
          sizeBytes: stats.size,
          type: items[i].name.endsWith('.json') ? 'json' : 'image',
          modified: stats.mtime.toISOString()
        });
      }
    }
  } catch (e) {}
  return results;
}

var allFiles = scanDir(basePath);
var categories = {};
var catNames = ['branding', 'ui-components', 'characters', 'onboarding', 'empty-states', 'backgrounds', 'comic-elements', 'icons', 'avatars', 'animations', 'design-system'];
catNames.forEach(function(cat) {
  categories[cat] = allFiles.filter(function(f) { return f.path.startsWith(cat + '/'); });
});

var manifest = {
  workflow: 'MangaKids Design Asset Generator',
  generatedAt: new Date().toISOString(),
  appName: 'MangaKids',
  totalAssets: allFiles.length,
  summary: {
    images: allFiles.filter(function(f) { return f.type === 'image'; }).length,
    jsonConfigs: allFiles.filter(function(f) { return f.type === 'json'; }).length,
    totalSizeBytes: allFiles.reduce(function(sum, f) { return sum + f.sizeBytes; }, 0)
  },
  categories: categories,
  outputStructure: {
    branding: 'Logo, app icon, store icon, splash screen',
